palette_overhaul.css:
/* ── PortalOS Design System v3 — Jet Black & Gold ── */

:root {
  /* BACKGROUNDS — true blacks with micro-contrast steps */
  --bg-void:        #000000;   /* absolute black — outermost shell, hero backgrounds */
  --bg-base:        #080808;   /* main app surface — 1 step above void */
  --bg-surface:     #0F0F0F;   /* cards, sidebar, panels */
  --bg-elevated:    #161616;   /* modals, dropdowns, popovers */
  --bg-sunken:      #050505;   /* inputs, inset wells, code blocks */
  --bg-overlay:     rgba(0, 0, 0, 0.85);  /* modal backdrop */

  /* INK — crisp, cold white hierarchy */
  --ink-primary:    #FFFFFF;   /* pure white — headlines only */
  --ink-secondary:  #B0B0B0;   /* body text, descriptions */
  --ink-tertiary:   #555555;   /* labels, captions, placeholders */
  --ink-ghost:      #222222;   /* barely visible decorative text */

  /* GOLD — the only accent color. Use surgically. */
  --gold-dim:       rgba(212, 175, 55, 0.06);   /* gold wash on surfaces */
  --gold-glow:      rgba(212, 175, 55, 0.12);   /* hover background tint */
  --gold-muted:     #6B5620;   /* inactive gold, decorative lines */
  --gold-base:      #9A7928;   /* secondary gold text, borders at rest */
  --gold-mid:       #C9A84C;   /* active states, numbers, amounts */
  --gold-core:      #D4AF37;   /* PRIMARY — buttons, active nav, focus */
  --gold-bright:    #E8CB6A;   /* hover on gold elements */
  --gold-light:     #F5E4A8;   /* hero display, maximum brightness gold */

  /* SEMANTIC — keep them tight, don't contaminate the palette */
  --success-bg:     rgba(20, 80, 40, 0.30);
  --success-text:   #4ADE80;
  --success-border: rgba(74, 222, 128, 0.25);

  --warning-bg:     rgba(212, 175, 55, 0.12);
  --warning-text:   var(--gold-bright);
  --warning-border: rgba(212, 175, 55, 0.30);

  --danger-bg:      rgba(180, 20, 20, 0.25);
  --danger-text:    #F87171;
  --danger-border:  rgba(248, 113, 113, 0.25);

  --neutral-bg:     rgba(255, 255, 255, 0.03);
  --neutral-text:   var(--ink-tertiary);
  --neutral-border: var(--border-hairline);

  /* BORDERS — the gold lines that define the luxury feel */
  --border-hairline:  rgba(255, 255, 255, 0.04);  /* barely there, card edges */
  --border-subtle:    rgba(255, 255, 255, 0.08);  /* hover reveal */
  --border-visible:   rgba(255, 255, 255, 0.14);  /* focused / selected */
  --border-gold-dim:  rgba(212, 175, 55, 0.20);   /* resting gold border */
  --border-gold:      rgba(212, 175, 55, 0.45);   /* active gold border */
  --border-gold-hot:  rgba(212, 175, 55, 0.75);   /* focused input, selected card */

  /* SHADOWS — deep blacks, no grey undertone */
  --shadow-xs:  0 1px 3px rgba(0, 0, 0, 0.60);
  --shadow-sm:  0 2px 8px rgba(0, 0, 0, 0.70),
                0 1px 2px rgba(0, 0, 0, 0.50);
  --shadow-md:  0 4px 20px rgba(0, 0, 0, 0.80),
                0 2px 6px  rgba(0, 0, 0, 0.60);
  --shadow-lg:  0 8px 40px rgba(0, 0, 0, 0.90),
                0 4px 12px rgba(0, 0, 0, 0.70);
  --shadow-xl:  0 20px 80px rgba(0, 0, 0, 0.95),
                0 8px 24px  rgba(0, 0, 0, 0.80);

  /* GOLD GLOW — earned, not decorative */
  --glow-gold-xs:  0 0 8px  rgba(212, 175, 55, 0.20);
  --glow-gold-sm:  0 2px 16px rgba(212, 175, 55, 0.30),
                   0 0 6px   rgba(212, 175, 55, 0.15);
  --glow-gold-md:  0 4px 30px rgba(212, 175, 55, 0.40),
                   0 0 12px  rgba(212, 175, 55, 0.20);
  --glow-gold-lg:  0 8px 60px rgba(212, 175, 55, 0.50),
                   0 0 24px  rgba(212, 175, 55, 0.25);

  /* INSET GLOW — selected card state */
  --inset-gold: inset 0 0 0 1px rgba(212, 175, 55, 0.40),
                inset 0 1px 0   rgba(212, 175, 55, 0.10);
  --inset-gold-hot: inset 0 0 0 1px rgba(212, 175, 55, 0.75),
                    inset 0 1px 0   rgba(212, 175, 55, 0.20);

  /* TYPOGRAPHY */
  --font-display: 'Playfair Display', Georgia, serif;
  --font-body:    'DM Sans', system-ui, sans-serif;
  --font-mono:    'JetBrains Mono', 'Fira Code', monospace;

  /* RADII — sharp. Nothing bubbly. */
  --radius-sm:   4px;
  --radius-md:   6px;
  --radius-lg:   8px;
  --radius-xl:   10px;
  --radius-pill: 999px;

  /* TRANSITIONS */
  --ease-out:   cubic-bezier(0.16, 1, 0.3, 1);
  --ease-in:    cubic-bezier(0.4, 0, 1, 1);
  --ease-circ:  cubic-bezier(0.0, 0.0, 0.2, 1);
  --t-fast:     120ms;
  --t-base:     200ms;
  --t-slow:     350ms;
  --t-xslow:    600ms;
}

/* ── LIGHT MODE — platinum, still premium ── */
[data-theme="light"] {
  --bg-void:       #E8E6E0;
  --bg-base:       #F2F0EA;
  --bg-surface:    #FAFAF8;
  --bg-elevated:   #FFFFFF;
  --bg-sunken:     #E0DED8;
  --ink-primary:   #0A0A0A;
  --ink-secondary: #4A4845;
  --ink-tertiary:  #8A8785;
  --border-hairline: rgba(0,0,0,0.06);
  --border-subtle:   rgba(0,0,0,0.10);
  --border-visible:  rgba(0,0,0,0.18);
  --gold-core:     #B8960A;
  --gold-mid:      #A07820;
  --shadow-sm: 0 2px 8px rgba(0,0,0,0.08), 0 1px 2px rgba(0,0,0,0.05);
  --shadow-md: 0 4px 20px rgba(0,0,0,0.10), 0 2px 6px rgba(0,0,0,0.06);
}

/* ── DEPTH LAYERS — reference guide ──
  Layer 0: --bg-void     absolute black / hero
  Layer 1: --bg-base     main app shell
  Layer 2: --bg-surface  sidebar, cards, panels
  Layer 3: --bg-elevated modals, dropdowns
  Layer 4: #1E1E1E        context menus, tooltips
*/

/* ── GLOBAL RESETS ── */
* { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; -webkit-font-smoothing: antialiased; }
body {
  background: var(--bg-void);
  color: var(--ink-secondary);
  font-family: var(--font-body);
  font-size: 15px;
  line-height: 1.7;
}

/* ── NOISE TEXTURE — matte surface feel ── */
body::after {
  content: '';
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 9999;
  opacity: 0.018;
  background-image: url("data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' width='200' height='200'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/></filter><rect width='200' height='200' filter='url(%23n)'/></svg>");
}

/* ── GOLD LINE RULE ── 
   The signature element. A 1px solid gold border on any element
   that should communicate: this matters.
*/
.gold-border   { border: 1px solid var(--border-gold-dim); }
.gold-border-active { border: 1px solid var(--border-gold); box-shadow: var(--inset-gold); }
.gold-border-hot    { border: 1px solid var(--border-gold-hot); box-shadow: var(--inset-gold-hot), var(--glow-gold-sm); }

/* ── CARDS ── */
.card {
  background: var(--bg-surface);
  border: 1px solid var(--border-hairline);
  border-top-color: rgba(255,255,255,0.08);   /* top edge catches light */
  border-radius: var(--radius-xl);
  transition: border-color var(--t-base) var(--ease-out),
              box-shadow   var(--t-base) var(--ease-out),
              transform    var(--t-base) var(--ease-out);
}
.card:hover {
  border-color: var(--border-subtle);
  box-shadow: var(--shadow-md);
  transform: translateY(-2px);
}
.card--gold {
  border-color: var(--border-gold-dim);
  box-shadow: var(--inset-gold), var(--shadow-sm);
  background: linear-gradient(135deg, var(--gold-dim) 0%, transparent 60%);
}
.card--gold:hover {
  border-color: var(--border-gold);
  box-shadow: var(--inset-gold), var(--shadow-md), var(--glow-gold-xs);
}

/* ── SKELETON SHIMMER ── */
@keyframes shimmer {
  0%   { background-position: -800px 0; }
  100% { background-position:  800px 0; }
}
.skeleton {
  background: linear-gradient(90deg,
    var(--bg-surface) 25%,
    var(--bg-elevated) 50%,
    var(--bg-surface) 75%
  );
  background-size: 1600px 100%;
  animation: shimmer 1.8s ease-in-out infinite;
  border-radius: var(--radius-md);
}

/* ── SCROLL REVEAL ── */
@keyframes reveal-up {
  from { opacity: 0; transform: translateY(24px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes reveal-fade {
  from { opacity: 0; }
  to   { opacity: 1; }
}
.reveal { opacity: 0; }
.reveal.in-view {
  animation: reveal-up var(--t-xslow) var(--ease-out) forwards;
}
.reveal-fade.in-view {
  animation: reveal-fade var(--t-xslow) var(--ease-out) forwards;
}

/* ── GOLD LINE SEPARATOR ── */
.gold-rule {
  width: 48px;
  height: 1px;
  background: var(--gold-core);
  margin: 0 auto;
  opacity: 0.8;
}
.gold-rule--left { margin: 0; }

floating_demo_cards.instruction:
The two demo cards on the landing page float independently.
Use CSS keyframe animation, NOT JavaScript (better performance):

@keyframes float-a {
  0%, 100% { transform: translateY(0px); }
  50%       { transform: translateY(-10px); }
}
@keyframes float-b {
  0%, 100% { transform: translateY(-6px); }
  50%       { transform: translateY(4px); }
}

Agency card: animation: float-a 4s ease-in-out infinite.
Client card: animation: float-b 4.8s ease-in-out 0.6s infinite.

On hover: animation-play-state: paused. Card lifts to its current float position.

page_transitions.instruction:
Wrap the agency app layout content area with a Framer Motion component:

initial={{ opacity: 0, y: 8 }}
animate={{ opacity: 1, y: 0 }}
transition={{ duration: 0.25, ease: [0.16, 1, 0.3, 1] }}
key={pathname} (use usePathname())

This gives a clean, fast, premium feel to every navigation action.
250ms is fast enough to not feel slow but noticeable enough to feel polished.
